  ('pukao-6e11b43e-moex-00299', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-112-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '在經適當警告或標示的開放山域、水域，人民從事冒險或具危險性活動時，因公共設施設置或管理有欠缺 而權利受損害，依據國家賠償法，下列何者為國家得減輕賠償責任之事由？', '["主管機關未獲求援呼救致未及時援助", "人民須事前向主管機關申請許可", "人民受損害之地點須在自然公物內之設施", "人民所受之損害須非財產上之權利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
