  ('pukao-6e11b43e-moex-00302', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-111-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '下列何者對於提高「直接公民參與」最無助益？', '["電子投票", "公民教育", "政府資料開放", "增加民意代表人數"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:32+00:00", "source_pdf_sha1": "9ac6946ceff5", "answer_pdf_sha1": "21f586edce14", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "413", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00303', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-111-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '古立克（L.H.Gulick）以「POSDCORB」來說明行政管理的七大項工作，提供員工培訓主要屬於下列那一 項工作的內涵？', '["P", "O", "S", "D"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:32+00:00", "source_pdf_sha1": "9ac6946ceff5", "answer_pdf_sha1": "21f586edce14", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "413", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
